class MyStack {
    LinkedList<Integer> front;
    LinkedList<Integer> rear;

    public MyStack() {
        front = new LinkedList<>();
        rear = new LinkedList<>();
    }

    public void push(int x) {
        rear.addLast(x);
    }

    public int pop() {
        if (isEmpty()) return -1;
        return front.removeFirst();
    }

    public int top() {
        if (isEmpty()) throw new RuntimeException("Stack underflow");
        return front.getFirst();
    }

    public boolean empty() {
        return front.isEmpty() && rear.isEmpty();
    }
}
```

